class Solution(object):
    def findTheLongestBalancedSubstring(self, s):
        max_len = 0
        i = 0
        while i < len(s):
            if s[i] == '1':
                i += 1
                continue
            zeros = 0
            while i < len(s) and s[i] == '0':
                zeros += 1
                i += 1
            ones = 0
            while i < len(s) and s[i] == '1':
                ones += 1
                i += 1
            max_len = max(max_len, 2 * min(zeros, ones))
        return max_len
